args.sparql:
SELECT ?country ?countryLabel ?size WHERE {
  ?country wdt:P31 wd:Q6256 ;  # sovereign state
          wdt:P30 wd:Q15 ;       # continent Africa
          wdt:P2171 ?size .
  FILTER(?size != "")
  OPTIONAL { ?country rdfs:label ?countryLabel FILTER(lang(?countryLabel) = "en") }
}
ORDER BY DESC(?size)
LIMIT 10

SELECT ?country ?size WHERE {
  ?country wdt:P31 wd:Q6256 ;  # sovereign state
          wdt:P30 wd:Q15 ;       # continent Africa
          wdt:P2131 ?size .     # military personnel count
  OPTIONAL { ?country rdfs:label ?label FILTER(lang(?label) = "en") }
}
ORDER BY DESC(xsd:integer(?size))

SELECT (COUNT(?larger) + 1 AS ?rank) WHERE {
  wd:Q974 wdt:P2171 ?drcSize .
  ?larger wdt:P2171 ?largerSize ;
         wdt:P31 wd:Q6256 ;
         wdt:P30 wd:Q15 .
  FILTER(?larger != wd:Q974)
  FILTER(xsd:integer(?largerSize) > xsd:integer(?drcSize))
  FILTER(ISNUMERIC(xsd:integer(?largerSize)))
  FILTER(ISNUMERIC(xsd:integer(?drcSize)))
}
